import { auth, db, signInWithEmailAndPassword, createUserWithEmailAndPassword, onAuthStateChanged, signOut, collection, addDoc, getDocs, doc, updateDoc, deleteDoc, query, orderBy, serverTimestamp } from './firebase.js';

const ADMIN_EMAIL='canecasdelrei@gmail.com';
const state={produtos:[],clientes:[],fornecedores:[],compras:[],vendas:[],pedidos:[],financeiro:[],caixas:[],usuarios:[],carrinho:[],pedidoItens:[],pagamento:'Dinheiro',user:null,perfil:'vendedora'};
const money=new Intl.NumberFormat('pt-BR',{style:'currency',currency:'BRL'}), dateBR=new Intl.DateTimeFormat('pt-BR');
function dataLocal(d=new Date()){const y=d.getFullYear(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0');return `${y}-${m}-${day}`}
const $=id=>document.getElementById(id), hoje=()=>dataLocal(), mes=()=>hoje().slice(0,7), fmt=v=>money.format(Number(v||0));
let chartDias, chartPag, chartResumo, ultimoOrcamento='';
function toast(msg){$('toast').textContent=msg;$('toast').classList.add('show');setTimeout(()=>$('toast').classList.remove('show'),2500)}
async function col(name,ord){try{const q=ord?query(collection(db,name),orderBy(ord,'desc')):collection(db,name);const s=await getDocs(q);return s.docs.map(d=>({id:d.id,...d.data()}))}catch(e){console.warn('coleção',name,e);return []}}
async function refresh(){state.produtos=await col('produtos','criadoEm'); state.clientes=await col('clientes','criadoEm'); state.fornecedores=await col('fornecedores','criadoEm'); state.compras=await col('compras','data'); state.vendas=await col('vendas','criadoEm'); state.pedidos=await col('pedidos','criadoEm'); state.financeiro=await col('financeiro','vencimento'); state.caixas=await col('caixas','abertoEm'); state.usuarios=await col('usuarios','criadoEm'); aplicarPermissoes(); renderAll()}
function renderAll(){renderProdutos();renderProdutosVenda();renderClientes();renderFornecedores();renderCompras();popularSelects();renderPedidoItens();renderPedidos();renderKanban();renderFinanceiro();renderCaixa();renderUsuarios();dashboard();relatorio();updatePedidoSaldo()}
function readFileBase64(input, cb){const f=input.files?.[0]; if(!f)return cb(''); const r=new FileReader(); r.onload=()=>cb(r.result); r.readAsDataURL(f)}

$('loginForm').addEventListener('submit',async e=>{e.preventDefault();try{await signInWithEmailAndPassword(auth,$('email').value.trim(),$('senha').value);toast('Login realizado')}catch(err){toast('Erro no login. Confira e-mail e senha.')}});
$('sair').addEventListener('click',()=>signOut(auth));
onAuthStateChanged(auth,async user=>{if(user){state.user=user;state.perfil=(user.email||'').toLowerCase()===ADMIN_EMAIL?'admin':'vendedora';$('login').classList.add('hidden');$('app').classList.remove('hidden');await garantirUsuarioAtual(user);await refresh()}else{state.user=null;state.perfil='vendedora';$('app').classList.add('hidden');$('login').classList.remove('hidden')}});
function isAdmin(){return state.perfil==='admin'}
async function garantirUsuarioAtual(user){const email=(user.email||'').toLowerCase();try{const users=await col('usuarios','criadoEm');const ja=users.find(u=>(u.email||'').toLowerCase()===email);const perfil=email===ADMIN_EMAIL?'admin':(ja?.perfil||'vendedora');state.perfil=perfil;if(!ja){await addDoc(collection(db,'usuarios'),{nome:email===ADMIN_EMAIL?'Administrador':'Usuário',email,perfil,ativo:true,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()})}else if(email===ADMIN_EMAIL&&ja.perfil!=='admin'){await updateDoc(doc(db,'usuarios',ja.id),{perfil:'admin',ativo:true,atualizadoEm:new Date().toISOString()});state.perfil='admin'}}catch(e){console.warn('usuarios',e)}}
function aplicarPermissoes(){const admin=isAdmin();document.querySelectorAll('.admin-only').forEach(el=>el.style.display=admin?'':'none');document.querySelectorAll('.vendedor-ok').forEach(el=>el.style.display='');if(!admin){const active=document.querySelector('.page.active');if(!active||active.classList.contains('admin-only'))document.querySelector('[data-page="pedidos"]').click();}}
function exigirAdmin(){if(!isAdmin()){toast('Acesso permitido apenas para administrador.');return false}return true}


const titles={dashboard:['Dashboard','Resumo geral da Canecas del Rei'],pedidos:['Pedidos','Orçamentos, vendas rápidas, artes, prazos e acompanhamento'],producao:['Produção','Kanban dos pedidos personalizados em andamento'],produtos:['Produtos','Cadastro e controle de estoque'],clientes:['Clientes','Cadastro completo de clientes'],fornecedores:['Fornecedores','Cadastro completo de fornecedores'],compras:['Compras','Entrada de estoque e saída financeira'],financeiro:['Financeiro','Contas a pagar, receber e fluxo previsto'],caixa:['Caixa','Abertura, movimentações e fechamento diário'],ia:['IA e WhatsApp','Textos inteligentes e orçamento rápido'],relatorios:['Relatórios','Fechamento por período e exportação CSV'],admin:['Administração','Usuários, permissões e limpeza de testes']};
document.querySelectorAll('.nav').forEach(b=>b.onclick=()=>{if(b.classList.contains('admin-only')&&!isAdmin())return exigirAdmin();document.querySelectorAll('.nav').forEach(x=>x.classList.remove('active'));document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));b.classList.add('active');$(b.dataset.page).classList.add('active');$('titulo').textContent=titles[b.dataset.page][0];$('subtitulo').textContent=titles[b.dataset.page][1]});
$('dataHoje').textContent=dateBR.format(new Date()); $('compraData').value=hoje(); $('relInicio').value=mes()+'-01'; $('relFim').value=hoje();

$('produtoImagemArquivo').addEventListener('change',()=>readFileBase64($('produtoImagemArquivo'),v=>{$('produtoImagem').value=v;toast('Imagem carregada no produto')}));
$('produtoForm').addEventListener('submit',async e=>{e.preventDefault();const id=$('produtoId').value;const p={nome:$('produtoNome').value.trim(),sku:$('produtoSku').value.trim(),categoria:$('produtoCategoria').value.trim(),preco:+$('produtoPreco').value||0,custo:+$('produtoCusto').value||0,estoque:+$('produtoEstoque').value||0,reservado:+$('produtoReservado').value||0,minimo:+$('produtoMinimo').value||0,fornecedorId:$('produtoFornecedor').value,imagem:$('produtoImagem').value.trim(),descricao:$('produtoDescricao').value.trim(),ativo:$('produtoAtivo').value==='true',atualizadoEm:new Date().toISOString()}; if(!p.nome||p.preco<=0)return toast('Informe nome e preço.'); if(id) await updateDoc(doc(db,'produtos',id),p); else await addDoc(collection(db,'produtos'),{...p,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()}); e.target.reset();$('produtoId').value='';$('produtoAtivo').value='true';toast('Produto salvo');refresh()});
$('cancelarProduto').onclick=()=>{$('produtoForm').reset();$('produtoId').value=''}; $('buscaProduto').oninput=renderProdutos; $('buscaVenda').oninput=renderProdutosVenda;
$('gerarDescProduto').onclick=()=>{const n=$('produtoNome').value||'Produto personalizado', cat=$('produtoCategoria').value||'personalizados';$('produtoDescricao').value=`${n} da Canecas del Rei, ideal para presentes criativos, lembranças e ações especiais. Produto da categoria ${cat}, com acabamento de qualidade e possibilidade de personalização conforme a necessidade do cliente. Perfeito para datas comemorativas, empresas, escolas e eventos.`;toast('Descrição sugerida gerada')};
function disponivel(p){return Math.max(0,(+p.estoque||0)-(+p.reservado||0))}
function renderProdutos(){const busca=($('buscaProduto').value||'').toLowerCase();const lista=state.produtos.filter(p=>[p.nome,p.sku,p.categoria].join(' ').toLowerCase().includes(busca));$('tabelaProdutos').innerHTML=lista.length?lista.map(p=>`<tr><td><b>${p.nome}</b><br><small>${p.sku||'Sem SKU'} ${p.imagem?'<br><img class="thumb" src="'+p.imagem+'">':''}</small></td><td>${p.categoria||'-'}</td><td>${fmt(p.preco)}</td><td>${fmt(p.custo)}</td><td><span class="badge ${(+p.estoque<=+p.minimo)?'gold':'green'}">${p.estoque||0}</span><br><small>Res.: ${p.reservado||0}</small></td><td>${disponivel(p)}</td><td>${p.ativo?'<span class="badge green">Ativo</span>':'<span class="badge red">Inativo</span>'}</td><td><button class="btn light" onclick="editProduto('${p.id}')">Editar</button> <button class="btn danger" onclick="delProduto('${p.id}')">Excluir</button></td></tr>`).join(''):'<tr><td colspan="8">Nenhum produto.</td></tr>'}
window.editProduto=id=>{const p=state.produtos.find(x=>x.id===id); if(!p)return; ['Id','Nome','Sku','Categoria','Preco','Custo','Estoque','Reservado','Minimo','Imagem','Descricao'].forEach(k=>{const el=$('produto'+k); if(el) el.value=p[k.charAt(0).toLowerCase()+k.slice(1)]||''});$('produtoFornecedor').value=p.fornecedorId||'';$('produtoAtivo').value=String(p.ativo!==false);document.querySelector('[data-page="produtos"]').click()};
window.delProduto=async id=>{if(confirm('Excluir produto?')){await deleteDoc(doc(db,'produtos',id));toast('Produto excluído');refresh()}};

$('clienteForm').addEventListener('submit',async e=>{e.preventDefault();const id=$('clienteId').value;const c={nome:$('clienteNome').value.trim(),whatsapp:$('clienteWhatsapp').value.trim(),email:$('clienteEmail').value.trim(),documento:$('clienteDocumento').value.trim(),instagram:$('clienteInstagram').value.trim(),cidade:$('clienteCidade').value.trim(),aniversario:$('clienteAniversario').value,origem:$('clienteOrigem').value.trim(),obs:$('clienteObs').value.trim(),atualizadoEm:new Date().toISOString()}; if(!c.nome)return toast('Informe o nome.'); if(id) await updateDoc(doc(db,'clientes',id),c); else await addDoc(collection(db,'clientes'),{...c,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()}); e.target.reset();$('clienteId').value='';toast('Cliente salvo');refresh()});
$('fornecedorForm').addEventListener('submit',async e=>{e.preventDefault();const id=$('fornecedorId').value;const f={nome:$('fornecedorNome').value.trim(),contato:$('fornecedorContato').value.trim(),whatsapp:$('fornecedorWhatsapp').value.trim(),cnpj:$('fornecedorCnpj').value.trim(),email:$('fornecedorEmail').value.trim(),prazo:$('fornecedorPrazo').value.trim(),categoria:$('fornecedorCategoria').value.trim(),obs:$('fornecedorObs').value.trim(),atualizadoEm:new Date().toISOString()}; if(!f.nome)return toast('Informe o fornecedor.'); if(id) await updateDoc(doc(db,'fornecedores',id),f); else await addDoc(collection(db,'fornecedores'),{...f,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()}); e.target.reset();$('fornecedorId').value='';toast('Fornecedor salvo');refresh()});
$('cancelarCliente').onclick=()=>{$('clienteForm').reset();$('clienteId').value=''}; $('cancelarFornecedor').onclick=()=>{$('fornecedorForm').reset();$('fornecedorId').value=''};
function renderClientes(){$('listaClientes').innerHTML=state.clientes.length?state.clientes.map(c=>`<div class="info"><div><strong>${c.nome}</strong><small>WhatsApp: ${c.whatsapp||'-'} | Cidade: ${c.cidade||'-'}</small><small>E-mail: ${c.email||'-'} | Instagram: ${c.instagram||'-'}</small><small>${c.obs||''}</small></div><div><button class="btn light" onclick="editCliente('${c.id}')">Editar</button> <button class="btn danger" onclick="delCliente('${c.id}')">Excluir</button></div></div>`).join(''):'<div class="empty">Nenhum cliente.</div>'}
function renderFornecedores(){$('listaFornecedores').innerHTML=state.fornecedores.length?state.fornecedores.map(f=>`<div class="info"><div><strong>${f.nome}</strong><small>Contato: ${f.contato||'-'} | WhatsApp: ${f.whatsapp||'-'}</small><small>CNPJ: ${f.cnpj||'-'} | Prazo: ${f.prazo||'-'}</small><small>${f.obs||''}</small></div><div><button class="btn light" onclick="editFornecedor('${f.id}')">Editar</button> <button class="btn danger" onclick="delFornecedor('${f.id}')">Excluir</button></div></div>`).join(''):'<div class="empty">Nenhum fornecedor.</div>'}
window.editCliente=id=>{const c=state.clientes.find(x=>x.id===id); ['Id','Nome','Whatsapp','Email','Documento','Instagram','Cidade','Aniversario','Origem','Obs'].forEach(k=>{const el=$('cliente'+k); if(el) el.value=c[k.charAt(0).toLowerCase()+k.slice(1)]||''});document.querySelector('[data-page="clientes"]').click()};
window.editFornecedor=id=>{const f=state.fornecedores.find(x=>x.id===id); ['Id','Nome','Contato','Whatsapp','Cnpj','Email','Prazo','Categoria','Obs'].forEach(k=>{const el=$('fornecedor'+k); if(el) el.value=f[k.charAt(0).toLowerCase()+k.slice(1)]||''});document.querySelector('[data-page="fornecedores"]').click()};
window.delCliente=async id=>{if(confirm('Excluir cliente?')){await deleteDoc(doc(db,'clientes',id));refresh()}}; window.delFornecedor=async id=>{if(confirm('Excluir fornecedor?')){await deleteDoc(doc(db,'fornecedores',id));refresh()}};

function popularSelects(){const keep={clienteVenda:$('clienteVenda')?.value||'',pedidoCliente:$('pedidoCliente')?.value||'',compraFornecedor:$('compraFornecedor')?.value||'',produtoFornecedor:$('produtoFornecedor')?.value||'',compraProduto:$('compraProduto')?.value||'',pedidoProduto:$('pedidoProduto')?.value||''};const cl='<option value="">Cliente não informado</option>'+state.clientes.map(c=>`<option value="${c.id}">${c.nome}</option>`).join('');$('clienteVenda').innerHTML=cl;$('pedidoCliente').innerHTML=cl;$('compraFornecedor').innerHTML='<option value="">Fornecedor não informado</option>'+state.fornecedores.map(f=>`<option value="${f.id}">${f.nome}</option>`).join('');$('produtoFornecedor').innerHTML='<option value="">Fornecedor não informado</option>'+state.fornecedores.map(f=>`<option value="${f.id}">${f.nome}</option>`).join('');const pr='<option value="">Selecione</option>'+state.produtos.map(p=>`<option value="${p.id}">${p.nome} - ${fmt(p.preco)}</option>`).join('');$('compraProduto').innerHTML='<option value="">Não atualizar estoque</option>'+state.produtos.map(p=>`<option value="${p.id}">${p.nome}</option>`).join('');$('pedidoProduto').innerHTML=pr;Object.entries(keep).forEach(([id,val])=>{if($(id))$(id).value=val});updatePedidoProdutoPreco()}

$('compraForm').addEventListener('submit',async e=>{e.preventDefault();const produtoId=$('compraProduto').value,qtd=+$('compraQtd').value||0,valor=+$('compraValor').value||0,status=$('compraStatus').value,metodo=$('compraMetodo').value,vencimento=$('compraVencimento').value||$('compraData').value,parcelas=Math.max(1,+$('compraParcelas').value||1);const compra={fornecedorId:$('compraFornecedor').value,produtoId,descricao:$('compraDescricao').value.trim(),quantidade:qtd,valor,data:$('compraData').value,status,metodo,vencimento,parcelas,obs:$('compraObs').value.trim(),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()};if(!compra.descricao||qtd<=0||valor<=0||!compra.data)return toast('Preencha a compra.');const ref=await addDoc(collection(db,'compras'),compra);for(let i=1;i<=parcelas;i++){await addDoc(collection(db,'financeiro'),{tipo:'pagar',descricao:`Compra: ${compra.descricao}${parcelas>1?' - parcela '+i+'/'+parcelas:''}`,pessoa:state.fornecedores.find(f=>f.id===compra.fornecedorId)?.nome||'',valor:valor/parcelas,vencimento,status,data:status==='Pago'?hoje():'',dataPagamento:status==='Pago'?hoje():'',metodo,compraId:ref.id,parcela:i,parcelas,competencia:compra.data.slice(0,7),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()})}if(produtoId){const p=state.produtos.find(x=>x.id===produtoId);await updateDoc(doc(db,'produtos',produtoId),{estoque:(+p.estoque||0)+qtd,atualizadoEm:new Date().toISOString()})}e.target.reset();$('compraData').value=hoje();$('compraParcelas').value=1;toast('Compra registrada');refresh()});
function renderCompras(){$('listaCompras').innerHTML=state.compras.length?state.compras.map(c=>`<div class="info"><div><strong>${c.descricao}</strong><small>Qtd: ${c.quantidade} | Valor: ${fmt(c.valor)}</small><small>Data: ${c.data?dateBR.format(new Date(c.data+'T00:00:00')):'-'}</small><small>${c.obs||''}</small></div></div>`).join(''):'<div class="empty">Nenhuma compra.</div>'}

function renderProdutosVenda(){const busca=($('buscaVenda').value||'').toLowerCase();const lista=state.produtos.filter(p=>p.ativo!==false&&[p.nome,p.sku,p.categoria].join(' ').toLowerCase().includes(busca));$('listaProdutosVenda').innerHTML=lista.length?lista.map(p=>`<button class="product" onclick="addVenda('${p.id}')">${p.imagem?'<img src="'+p.imagem+'">':''}<strong>${p.nome}</strong><small>${p.categoria||'Sem categoria'} | Disp.: ${disponivel(p)}</small><span>${fmt(p.preco)}</span></button>`).join(''):'<div class="empty">Nenhum produto ativo.</div>'}
document.querySelectorAll('.pay').forEach(b=>b.onclick=()=>{document.querySelectorAll('.pay').forEach(x=>x.classList.remove('active'));b.classList.add('active');state.pagamento=b.dataset.pay}); $('descontoVenda').oninput=renderCarrinho; $('limparVenda').onclick=()=>{state.carrinho=[];$('descontoVenda').value=0;$('obsVenda').value='';renderCarrinho()};
window.addVenda=id=>{const p=state.produtos.find(x=>x.id===id);const item=state.carrinho.find(x=>x.id===id); if(item)item.qtd++; else state.carrinho.push({id:p.id,nome:p.nome,preco:+p.preco||0,custo:+p.custo||0,qtd:1}); renderCarrinho()};
window.qtdVenda=(id,d)=>{const i=state.carrinho.find(x=>x.id===id); if(!i)return; i.qtd+=d; if(i.qtd<=0)state.carrinho=state.carrinho.filter(x=>x.id!==id); renderCarrinho()};
function renderCarrinho(){const sub=state.carrinho.reduce((s,i)=>s+i.preco*i.qtd,0), desc=+$('descontoVenda').value||0,total=Math.max(0,sub-desc);$('totalVenda').textContent=fmt(total);$('carrinho').className=state.carrinho.length?'':'empty';$('carrinho').innerHTML=state.carrinho.length?state.carrinho.map(i=>`<div class="cart-item"><div><b>${i.nome}</b><br><small>${fmt(i.preco)} cada</small></div><button class="qty" onclick="qtdVenda('${i.id}',-1)">-</button><b>${i.qtd}</b><button class="qty" onclick="qtdVenda('${i.id}',1)">+</button><b>${fmt(i.preco*i.qtd)}</b></div>`).join(''):'Nenhum produto adicionado.'}
$('finalizarVenda').onclick=async()=>{if(!state.carrinho.length)return toast('Adicione produto.');const desc=+$('descontoVenda').value||0,sub=state.carrinho.reduce((s,i)=>s+i.preco*i.qtd,0),custo=state.carrinho.reduce((s,i)=>s+i.custo*i.qtd,0),total=Math.max(0,sub-desc),cliente=state.clientes.find(c=>c.id===$('clienteVenda').value);const venda={data:hoje(),mes:mes(),clienteId:cliente?.id||'',clienteNome:cliente?.nome||'',pagamento:state.pagamento,desconto:desc,subtotal:sub,total,custoTotal:custo,lucro:total-custo,obs:$('obsVenda').value.trim(),itens:state.carrinho.map(i=>({produtoId:i.id,nome:i.nome,preco:i.preco,custo:i.custo,quantidade:i.qtd,subtotal:i.preco*i.qtd,lucro:(i.preco-i.custo)*i.qtd})),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()}; await addDoc(collection(db,'vendas'),venda); await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Venda à vista',pessoa:cliente?.nome||'',valor:total,vencimento:hoje(),status:'Pago',data:hoje(),dataPagamento:hoje(),metodo:state.pagamento,competencia:mes(),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()}); for(const i of state.carrinho){const p=state.produtos.find(x=>x.id===i.id);await updateDoc(doc(db,'produtos',i.id),{estoque:Math.max(0,(+p.estoque||0)-i.qtd),atualizadoEm:new Date().toISOString()})} state.carrinho=[];$('descontoVenda').value=0;$('obsVenda').value='';renderCarrinho();toast('Venda finalizada');refresh()};



$('pedidoImagemArquivo').addEventListener('change',()=>readFileBase64($('pedidoImagemArquivo'),v=>{$('pedidoImagem').value=v;toast('Imagem da arte carregada')})); $('buscaPedido').oninput=renderPedidos;
function pedidoTotals(){const subtotal=state.pedidoItens.reduce((s,i)=>s+(+i.preco||0)*(+i.quantidade||0),0),desconto=+$('pedidoDesconto').value||0,total=Math.max(0,subtotal-desconto),sinal=Math.min(total,+$('pedidoSinal').value||0),saldo=Math.max(0,total-sinal);return {subtotal,desconto,total,sinal,saldo}}
function updatePedidoProdutoPreco(){const prod=state.produtos.find(p=>p.id===$('pedidoProduto').value);if($('pedidoPrecoUnit'))$('pedidoPrecoUnit').value=prod?fmt(prod.preco):fmt(0)}
function updatePedidoSaldo(){const t=pedidoTotals();if($('pedidoSubtotal'))$('pedidoSubtotal').value=fmt(t.subtotal);if($('pedidoValor'))$('pedidoValor').value=fmt(t.total);if($('pedidoSaldo'))$('pedidoSaldo').value=fmt(t.saldo);renderPedidoResumo(t)}
function renderPedidoResumo(t=pedidoTotals()){const box=$('pedidoItens');if(!box)return;const resumo=document.querySelector('.pedido-resumo');if(resumo)resumo.innerHTML=`<span>Subtotal: ${fmt(t.subtotal)}</span><span>Desconto: ${fmt(t.desconto)}</span><span>Total: ${fmt(t.total)}</span><span>Sinal: ${fmt(t.sinal)}</span><span>Saldo: ${fmt(t.saldo)}</span>`}
function renderPedidoItens(){const box=$('pedidoItens');if(!box)return;if(!state.pedidoItens.length){box.className='pedido-itens empty';box.innerHTML='Nenhum produto adicionado.';updatePedidoSaldo();return}box.className='pedido-itens';box.innerHTML=state.pedidoItens.map((i,idx)=>`<div class="pedido-item-row"><div><b>${i.nome}</b><br><small>${fmt(i.preco)} cada | Subtotal: ${fmt((+i.preco||0)*(+i.quantidade||0))}</small></div><input type="number" min="1" value="${i.quantidade}" onchange="pedidoItemQtd(${idx},this.value)"><input type="number" min="0" step="0.01" value="${i.preco}" onchange="pedidoItemPreco(${idx},this.value)"><b>${fmt((+i.preco||0)*(+i.quantidade||0))}</b><button type="button" class="btn danger" onclick="pedidoItemRemove(${idx})">Remover</button></div>`).join('')+'<div class="pedido-resumo"></div>';updatePedidoSaldo()}
function addPedidoItem(){const prod=state.produtos.find(p=>p.id===$('pedidoProduto').value),qtd=+$('pedidoQtd').value||1;if(!prod)return toast('Selecione um produto.');const item=state.pedidoItens.find(i=>i.produtoId===prod.id);if(item)item.quantidade+=qtd;else state.pedidoItens.push({produtoId:prod.id,nome:prod.nome,preco:+prod.preco||0,custo:+prod.custo||0,quantidade:qtd});$('pedidoQtd').value=1;renderPedidoItens();toast('Produto adicionado ao pedido')}
window.pedidoItemQtd=(idx,v)=>{state.pedidoItens[idx].quantidade=Math.max(1,+v||1);renderPedidoItens()};
window.pedidoItemPreco=(idx,v)=>{state.pedidoItens[idx].preco=Math.max(0,+v||0);renderPedidoItens()};
window.pedidoItemRemove=idx=>{state.pedidoItens.splice(idx,1);renderPedidoItens()};
function ajustarPedidoPorTipo(){if(!$('pedidoTipo'))return;const tipo=$('pedidoTipo').value;if(tipo==='pronto'){$('pedidoStatus').value='Entregue';$('pedidoEntrega').value=$('pedidoEntrega').value||hoje();$('pedidoArte').placeholder='Não obrigatório para produto pronto';}else{$('pedidoArte').placeholder='Link do arquivo ou descrição';if($('pedidoStatus').value==='Entregue')$('pedidoStatus').value='Orçamento';}}
$('pedidoProduto').addEventListener('change',updatePedidoProdutoPreco);$('pedidoQtd').addEventListener('input',updatePedidoProdutoPreco);$('addPedidoItem').addEventListener('click',addPedidoItem);$('pedidoDesconto').addEventListener('input',updatePedidoSaldo);$('pedidoSinal').addEventListener('input',updatePedidoSaldo);$('pedidoTipo').addEventListener('change',ajustarPedidoPorTipo);
function limparPedidoForm(){const img=$('pedidoImagem').value;$('pedidoForm').reset();$('pedidoId').value='';$('pedidoImagem').value='';$('pedidoQtd').value=1;$('pedidoSinal').value=0;$('pedidoDesconto').value=0;if($('pedidoMetodoSinal'))$('pedidoMetodoSinal').value='Pix';if($('pedidoMetodoRestante'))$('pedidoMetodoRestante').value='Pix';state.pedidoItens=[];renderPedidoItens();updatePedidoProdutoPreco();updatePedidoSaldo()}
function itensDoPedido(p){if(Array.isArray(p.itens)&&p.itens.length)return p.itens;return p.produtoId?[{produtoId:p.produtoId,nome:p.produtoNome,preco:(+p.valor||0)/(+p.quantidade||1),custo:+p.custo||0,quantidade:+p.quantidade||1}]:[]}
function pedidoProdutosTexto(p){return itensDoPedido(p).map(i=>`${i.quantidade}x ${i.nome}`).join(', ')}
$('pedidoForm').addEventListener('submit',async e=>{e.preventDefault();const id=$('pedidoId').value, cliente=state.clientes.find(c=>c.id===$('pedidoCliente').value), tipo=$('pedidoTipo').value||'personalizado';const t=pedidoTotals();let status=$('pedidoStatus').value,pagamento=$('pedidoPagamento').value;if(pagamento==='Pago'&&t.total>0){t.sinal=t.total;t.saldo=0;$('pedidoSinal').value=t.total;updatePedidoSaldo()}if(tipo==='pronto'){status='Entregue'; if(t.total>0&&t.sinal>=t.total) pagamento='Pago'}else if(t.sinal>0&&t.saldo>0){pagamento='Sinal pago'}else if(t.total>0&&t.saldo===0){pagamento='Pago'}if(!cliente?.nome)return toast('Informe o cliente.'); if(!state.pedidoItens.length)return toast('Adicione pelo menos um produto.');const pedidoAnterior=id?state.pedidos.find(x=>x.id===id):null, valorRecebidoEdicao=Math.max(0,(+t.sinal||0)-(+pedidoAnterior?.sinal||0));const itens=state.pedidoItens.map(i=>({produtoId:i.produtoId,nome:i.nome,preco:+i.preco||0,custo:+i.custo||0,quantidade:+i.quantidade||1,subtotal:(+i.preco||0)*(+i.quantidade||1),lucro:((+i.preco||0)-(+i.custo||0))*(+i.quantidade||1)}));const custoTotal=itens.reduce((s,i)=>s+(+i.custo||0)*(+i.quantidade||0),0);const produtoNome=itens.map(i=>i.nome).join(', ');const quantidadeTotal=itens.reduce((s,i)=>s+(+i.quantidade||0),0);const pedido={tipo,clienteId:cliente.id,clienteNome:cliente.nome,clienteWhatsapp:cliente.whatsapp||'',itens,produtoId:itens[0]?.produtoId||'',produtoNome,quantidade:quantidadeTotal,subtotal:t.subtotal,desconto:t.desconto,valor:t.total,sinal:t.sinal,saldo:t.saldo,entrega:$('pedidoEntrega').value,status,arte:$('pedidoArte').value.trim(),imagem:$('pedidoImagem').value,pagamento,metodoSinal:$('pedidoMetodoSinal')?.value||'Pix',metodoRestante:$('pedidoMetodoRestante')?.value||'Pix',vendaFinalizada:tipo==='pronto',obs:$('pedidoObs').value.trim(),atualizadoEm:new Date().toISOString()};if(id){await updateDoc(doc(db,'pedidos',id),pedido);if(valorRecebidoEdicao>0) await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Pagamento do pedido editado: '+produtoNome,pessoa:pedido.clienteNome,metodo:pedido.saldo>0?pedido.metodoSinal:pedido.metodoRestante,valor:valorRecebidoEdicao,vencimento:hoje(),status:'Pago',data:hoje(),pedidoId:id,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()})}else{await addDoc(collection(db,'pedidos'),{...pedido,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});if(tipo==='pronto'){await addDoc(collection(db,'vendas'),{data:hoje(),mes:mes(),clienteId:pedido.clienteId,clienteNome:pedido.clienteNome,pagamento:$('pedidoMetodoRestante')?.value||'Pix',desconto:t.desconto,subtotal:t.subtotal,total:t.total,custoTotal,lucro:t.total-custoTotal,obs:pedido.obs,itens,origem:'pedido',criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Pedido pronto: '+produtoNome,pessoa:pedido.clienteNome,metodo:$('pedidoMetodoRestante')?.value||'Pix',valor:t.total,vencimento:hoje(),status:t.sinal>=t.total?'Pago':'Pendente',data:hoje(),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});for(const i of itens){const prod=state.produtos.find(x=>x.id===i.produtoId);if(prod?.id)await updateDoc(doc(db,'produtos',prod.id),{estoque:Math.max(0,(+prod.estoque||0)-(+i.quantidade||0)),atualizadoEm:new Date().toISOString()})}}else{if(t.sinal>0) await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Sinal do pedido: '+produtoNome,pessoa:pedido.clienteNome,metodo:$('pedidoMetodoSinal')?.value||'Pix',valor:t.sinal,vencimento:hoje(),status:'Pago',data:hoje(),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()}); if(t.saldo>0) await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Saldo restante do pedido: '+produtoNome,pessoa:pedido.clienteNome,metodo:$('pedidoMetodoRestante')?.value||'Pix',valor:t.saldo,vencimento:pedido.entrega||hoje(),status:'Pendente',data:hoje(),criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});for(const i of itens){const prod=state.produtos.find(x=>x.id===i.produtoId);if(prod?.id)await updateDoc(doc(db,'produtos',prod.id),{reservado:(+prod.reservado||0)+(+i.quantidade||0),atualizadoEm:new Date().toISOString()})}}}limparPedidoForm();toast('Pedido salvo');refresh()});
$('cancelarPedido').onclick=limparPedidoForm;
function renderPedidos(){const busca=($('buscaPedido').value||'').toLowerCase();const lista=state.pedidos.filter(p=>[p.clienteNome,p.produtoNome,p.status,p.tipo,p.obs,pedidoProdutosTexto(p)].join(' ').toLowerCase().includes(busca));$('listaPedidos').innerHTML=lista.length?lista.map(p=>`<div class="info"><div>${p.imagem?'<img class="thumb" src="'+p.imagem+'">':''}<strong>${p.clienteNome}</strong><small>Itens: ${pedidoProdutosTexto(p)||'-'}</small><small>Tipo: ${p.tipo==='pronto'?'Produto pronto / venda rápida':'Produto personalizado'} | Entrega: ${p.entrega||'-'}</small><small>Subtotal: ${fmt(p.subtotal??p.valor)} | Desconto: ${fmt(p.desconto||0)} | Total: ${fmt(p.valor)} | Sinal: ${fmt(p.sinal||0)} | Saldo: ${fmt(p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0)))}</small><small>Status: <b>${p.status}</b> | Pagamento: ${p.pagamento||'-'}</small><div class="payment-mini"><span class="badge">Sinal: ${p.metodoSinal||'Pix'}</span><span class="badge">Restante: ${p.metodoRestante||'Pix'}</span></div><small>${p.obs||''}</small></div><div class="actions col"><button class="btn light" onclick="editPedido('${p.id}')">Editar</button><button class="btn goldbtn" onclick="receberRestanteEFinalizar('${p.id}')">Receber saldo / finalizar</button><button class="btn light" onclick="printOP('${p.id}')">OP/PDF</button><button class="btn light" onclick="whatsPedido('${p.id}')">WhatsApp</button><button class="btn danger" onclick="delPedido('${p.id}')">Excluir</button></div></div>`).join(''):'<div class="empty">Nenhum pedido.</div>'}
window.editPedido=id=>{const p=state.pedidos.find(x=>x.id===id);$('pedidoId').value=p.id;$('pedidoTipo').value=p.tipo||'personalizado';$('pedidoCliente').value=p.clienteId||'';state.pedidoItens=itensDoPedido(p).map(i=>({...i,preco:+i.preco||0,custo:+i.custo||0,quantidade:+i.quantidade||1}));$('pedidoDesconto').value=p.desconto||0;$('pedidoSinal').value=p.sinal||0;$('pedidoEntrega').value=p.entrega||'';$('pedidoStatus').value=p.status||'Orçamento';$('pedidoArte').value=p.arte||'';$('pedidoImagem').value=p.imagem||'';$('pedidoPagamento').value=p.pagamento||'Pendente';if($('pedidoMetodoSinal'))$('pedidoMetodoSinal').value=p.metodoSinal||'Pix';if($('pedidoMetodoRestante'))$('pedidoMetodoRestante').value=p.metodoRestante||'Pix';$('pedidoObs').value=p.obs||'';renderPedidoItens();updatePedidoSaldo();document.querySelector('[data-page="pedidos"]').click()};
window.delPedido=async id=>{if(confirm('Excluir pedido?')){await deleteDoc(doc(db,'pedidos',id));refresh()}};
window.whatsPedido=id=>{const p=state.pedidos.find(x=>x.id===id);const n=(p.clienteWhatsapp||'').replace(/\D/g,'');const saldo=p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0));const msg=`Olá ${p.clienteNome}! Seu pedido (${pedidoProdutosTexto(p)}) está com status: ${p.status}. Previsão de entrega: ${p.entrega||'a confirmar'}. Valor total: ${fmt(p.valor)}. Desconto: ${fmt(p.desconto||0)}. Sinal pago: ${fmt(p.sinal||0)}. Saldo restante: ${fmt(saldo)}.`;window.open(`https://wa.me/55${n}?text=${encodeURIComponent(msg)}`,'_blank')};
window.printOP=id=>{const p=state.pedidos.find(x=>x.id===id);const saldo=p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0));const itens=itensDoPedido(p).map(i=>`<tr><td>${i.nome}</td><td>${i.quantidade}</td><td>${fmt(i.preco)}</td><td>${fmt((+i.preco||0)*(+i.quantidade||0))}</td></tr>`).join('');const w=window.open('','_blank');w.document.write(`<html><head><title>Ordem de Produção</title><style>body{font-family:Arial;padding:30px}h1{color:#123c69}.box{border:1px solid #ddd;border-radius:14px;padding:14px;margin:12px 0}img{max-width:260px}table{width:100%;border-collapse:collapse}td,th{border-bottom:1px solid #ddd;padding:8px;text-align:left}</style></head><body><h1>Ordem de Produção - Canecas del Rei</h1><div class='box'><b>Cliente:</b> ${p.clienteNome}<br><b>Tipo:</b> ${p.tipo==='pronto'?'Produto pronto / venda rápida':'Produto personalizado'}<br><b>Entrega:</b> ${p.entrega||'-'}<br><b>Status:</b> ${p.status}<br><b>Subtotal:</b> ${fmt(p.subtotal??p.valor)}<br><b>Desconto:</b> ${fmt(p.desconto||0)}<br><b>Total:</b> ${fmt(p.valor)}<br><b>Sinal pago:</b> ${fmt(p.sinal||0)}<br><b>Saldo restante:</b> ${fmt(saldo)}</div><div class='box'><h3>Itens</h3><table><thead><tr><th>Produto</th><th>Qtd</th><th>Unit.</th><th>Total</th></tr></thead><tbody>${itens}</tbody></table></div><div class='box'><b>Arte:</b> ${p.arte||'-'}<br><b>Observações:</b><br>${p.obs||'-'}</div>${p.imagem?`<img src='${p.imagem}'>`:''}<script>window.print()<\/script></body></html>`);w.document.close()};

async function finalizarVendaDoPedido(p,metodo){if(!p||p.vendaFinalizada)return;const itens=itensDoPedido(p);const custoTotal=itens.reduce((s,i)=>s+(+i.custo||0)*(+i.quantidade||0),0);await addDoc(collection(db,'vendas'),{data:hoje(),mes:mes(),clienteId:p.clienteId,clienteNome:p.clienteNome,pagamento:metodo||p.metodoRestante||'Pix',desconto:+p.desconto||0,subtotal:+(p.subtotal??p.valor)||0,total:+p.valor||0,custoTotal,lucro:(+p.valor||0)-custoTotal,obs:p.obs||'',itens,origem:'pedido',pedidoId:p.id,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});for(const i of itens){const prod=state.produtos.find(x=>x.id===i.produtoId);if(prod?.id){const novoEstoque=Math.max(0,(+prod.estoque||0)-(+i.quantidade||0));const novoReservado=Math.max(0,(+prod.reservado||0)-(+i.quantidade||0));await updateDoc(doc(db,'produtos',prod.id),{estoque:novoEstoque,reservado:novoReservado,atualizadoEm:new Date().toISOString()})}}await updateDoc(doc(db,'pedidos',p.id),{vendaFinalizada:true,status:'Entregue',pagamento:'Pago',saldo:0,atualizadoEm:new Date().toISOString()})}
window.registrarPagamentoPedido=async(id)=>{const p=state.pedidos.find(x=>x.id===id);if(!p)return;const valor=+$('payValor_'+id)?.value||0,metodo=$('payMetodo_'+id)?.value||p.metodoRestante||'Pix';if(valor<=0)return toast('Informe o valor recebido.');const total=+p.valor||0,pagoAtual=+p.sinal||0,novoPago=Math.min(total,pagoAtual+valor),novoSaldo=Math.max(0,total-novoPago),novoStatusPg=novoSaldo===0?'Pago':'Sinal pago';await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Pagamento do pedido: '+pedidoProdutosTexto(p),pessoa:p.clienteNome,metodo,valor,vencimento:hoje(),status:'Pago',data:hoje(),pedidoId:id,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});await updateDoc(doc(db,'pedidos',id),{sinal:novoPago,saldo:novoSaldo,pagamento:novoStatusPg,metodoRestante:metodo,atualizadoEm:new Date().toISOString()});toast('Pagamento registrado');refresh()};
window.receberRestanteEFinalizar=async(id)=>{const p=state.pedidos.find(x=>x.id===id);if(!p)return;const saldo=p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0));let metodo=prompt('Forma de pagamento do restante (Pix, Dinheiro, Crédito, Débito):',p.metodoRestante||'Pix')||p.metodoRestante||'Pix';let valor=saldo>0?Number(String(prompt('Valor recebido agora:',saldo.toFixed(2))||'0').replace(',','.')):0;if(saldo>0){if(!valor||valor<=0)return toast('Valor não informado.');await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:'Saldo final do pedido: '+pedidoProdutosTexto(p),pessoa:p.clienteNome,metodo,valor,vencimento:hoje(),status:'Pago',data:hoje(),pedidoId:id,criadoEm:new Date().toISOString(),timestamp:serverTimestamp()})}const novoPago=Math.min(+p.valor||0,(+p.sinal||0)+(valor||0));const novoSaldo=Math.max(0,(+p.valor||0)-novoPago);await updateDoc(doc(db,'pedidos',id),{sinal:novoPago,saldo:novoSaldo,pagamento:novoSaldo===0?'Pago':'Sinal pago',metodoRestante:metodo,status:novoSaldo===0?'Entregue':(p.status||'Pronto'),atualizadoEm:new Date().toISOString()});const atualizado={...p,sinal:novoPago,saldo:novoSaldo,metodoRestante:metodo,status:novoSaldo===0?'Entregue':p.status};if(novoSaldo===0)await finalizarVendaDoPedido(atualizado,metodo);toast('Pedido atualizado');refresh()};
let productionView='ativos';
const productionActiveStatuses=['Orçamento','Pedido aprovado','Arte em criação','Aguardando aprovação','Produção'];
function productionMatches(p){
  const q=($('buscaProducao')?.value||'').trim().toLowerCase();
  const prazo=$('filtroPrazoProducao')?.value||'todos';
  const text=[p.clienteNome,p.produtoNome,p.obs,pedidoProdutosTexto(p)].join(' ').toLowerCase();
  if(q&&!text.includes(q))return false;
  if(prazo==='hoje'&&p.entrega!==hoje())return false;
  if(prazo==='sem-data'&&p.entrega)return false;
  if(prazo==='semana'){
    if(!p.entrega)return false;
    const limite=new Date();limite.setDate(limite.getDate()+7);
    if(p.entrega<hoje()||p.entrega>dataLocal(limite))return false;
  }
  return true;
}
function dueLabel(p){
  if(!p.entrega)return '<span class="due">Sem prazo</span>';
  const overdue=p.entrega<hoje()&&!['Entregue','Cancelado'].includes(p.status);
  const label=p.entrega===hoje()?'Hoje':dateBR.format(new Date(p.entrega+'T00:00:00'));
  return `<span class="due ${overdue?'overdue':''}">${overdue?'Atrasado • ':''}${label}</span>`;
}
function productionListCard(p,kind){
  const saldo=p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0));
  const overdue=p.entrega&&p.entrega<hoje()&&!['Entregue','Cancelado'].includes(p.status);
  return `<div class="production-list-card ${overdue?'overdue':''}"><div><h4>${p.clienteNome||'Cliente não informado'}</h4><small>${pedidoProdutosTexto(p)||'Sem produtos'}</small><small>Status: <b>${p.status}</b> • Entrega: ${p.entrega?dateBR.format(new Date(p.entrega+'T00:00:00')):'Sem data'} • Total: ${fmt(p.valor)}</small><small>Pago: ${fmt(p.sinal||0)} • Saldo: ${fmt(saldo)} • ${p.pagamento||'Pagamento não informado'}</small></div><div class="production-list-actions"><button class="btn light" onclick="editPedido('${p.id}')">Abrir pedido</button>${kind==='prontos'?`<button class="btn goldbtn" onclick="receberRestanteEFinalizar('${p.id}')">Entregar / finalizar</button>`:`<button class="btn primary" onclick="movePedido('${p.id}','Produção')">Mover para produção</button>`}</div></div>`;
}
function renderKanban(){
  const ativos=state.pedidos.filter(p=>productionActiveStatuses.includes(p.status));
  const atrasados=state.pedidos.filter(p=>p.entrega&&p.entrega<hoje()&&!['Entregue','Cancelado'].includes(p.status));
  const prontos=state.pedidos.filter(p=>p.status==='Pronto');
  const finalizados=state.pedidos.filter(p=>['Entregue','Cancelado'].includes(p.status));
  if($('countAtivos'))$('countAtivos').textContent=ativos.length;
  if($('countAtrasados'))$('countAtrasados').textContent=atrasados.length;
  if($('countProntos'))$('countProntos').textContent=prontos.length;
  if($('countFinalizados'))$('countFinalizados').textContent=finalizados.length;

  const responsaveis=[...new Set(ativos.map(p=>p.responsavel||p.criadoPor||'Não atribuído'))].sort();
  const respSelect=$('filtroResponsavelProducao');
  if(respSelect){const atual=respSelect.value;respSelect.innerHTML='<option value="todos">Responsável</option>'+responsaveis.map(r=>`<option>${r}</option>`).join('');respSelect.value=[...respSelect.options].some(o=>o.value===atual)?atual:'todos'}
  const tipos=[...new Set(ativos.flatMap(p=>itensDoPedido(p).map(i=>i.nome||i.produtoNome).filter(Boolean)))].sort();
  const tipoSelect=$('filtroProdutoProducao');
  if(tipoSelect){const atual=tipoSelect.value;tipoSelect.innerHTML='<option value="todos">Tipo de produto</option>'+tipos.map(t=>`<option>${t}</option>`).join('');tipoSelect.value=[...tipoSelect.options].some(o=>o.value===atual)?atual:'todos'}

  const filtered=ativos.filter(productionMatches).sort((a,b)=>(a.entrega||'9999').localeCompare(b.entrega||'9999'));
  const stageMeta={
    'Orçamento':{number:'1.',cls:'stage-budget'},
    'Pedido aprovado':{number:'2.',cls:'stage-approved'},
    'Arte em criação':{number:'3.',cls:'stage-art'},
    'Aguardando aprovação':{number:'4.',cls:'stage-waiting'},
    'Produção':{number:'5.',cls:'stage-production'}
  };
  if($('kanban'))$('kanban').innerHTML=productionActiveStatuses.map(st=>{
    const cards=filtered.filter(p=>p.status===st),meta=stageMeta[st]||{number:'',cls:''};
    return `<div class="kanban-col ${meta.cls}" data-status="${st}"><div class="kanban-col-head"><h3>${meta.number} ${st}</h3><span class="kanban-count">${cards.length}</span></div><div class="kanban-cards">${cards.map(p=>{
      const saldo=p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0));
      const numero=String(p.numero||p.codigo||p.id||'').replace(/\D/g,'').slice(-4)||String((state.pedidos.indexOf(p)+1)).padStart(4,'0');
      const responsavel=p.responsavel||p.criadoPor||$('userNameTop')?.textContent||'Equipe';
      const initials=responsavel.split(/\s+/).map(x=>x[0]).join('').slice(0,2).toUpperCase();
      const tipo=(itensDoPedido(p)[0]?.categoria||p.tipo||'Personalizado').replace('personalizado','Personalizado').replace('pronto','Produto pronto');
      const progresso=st==='Produção'?Math.max(20,Math.min(90,+p.progresso||50)):0;
      return `<div class="kanban-card ${p.entrega&&p.entrega<hoje()?'is-overdue':''}" draggable="true" data-pedido-id="${p.id}" onclick="if(!event.target.closest('button,select'))editPedido('${p.id}')">
        <div class="kanban-card-top"><b>#${numero}</b>${dueLabel(p)}</div>
        <h4>${p.clienteNome||'Cliente não informado'}</h4>
        <p>${pedidoProdutosTexto(p)||'Sem produtos cadastrados'}</p>
        <small class="card-total">Total: ${fmt(p.valor)}</small>
        <div class="card-owner"><span>${initials}</span><small>${responsavel}</small></div>
        <div class="card-footer"><span class="product-chip">${tipo}</span>${st==='Aguardando aprovação'?'<em>◷ Aguardando cliente</em>':''}</div>
        ${st==='Produção'?`<div class="production-progress"><small>Produção ${progresso}%</small><div><i style="width:${progresso}%"></i></div></div>`:''}
        <div class="kanban-card-controls"><select aria-label="Alterar etapa" onchange="movePedido('${p.id}',this.value)">${[...productionActiveStatuses,'Pronto','Cancelado'].map(x=>`<option ${x===p.status?'selected':''}>${x}</option>`).join('')}</select>${saldo>0?`<button class="mini-pay" onclick="event.stopPropagation();registrarPagamentoRapido('${p.id}')">Receber</button>`:''}</div>
      </div>`}).join('')||'<div class="kanban-empty">Nenhum pedido nesta etapa.</div>'}<button class="add-card-button" type="button" onclick="document.getElementById('novoPedidoProducao').click()">＋ &nbsp; Adicionar cartão</button></div></div>`;
  }).join('');
  if($('listaAtrasados'))$('listaAtrasados').innerHTML=atrasados.filter(productionMatches).sort((a,b)=>(a.entrega||'').localeCompare(b.entrega||'')).map(p=>productionListCard(p,'atrasados')).join('')||'<div class="empty">Nenhum pedido atrasado.</div>';
  if($('listaProntos'))$('listaProntos').innerHTML=prontos.filter(productionMatches).sort((a,b)=>(a.entrega||'9999').localeCompare(b.entrega||'9999')).map(p=>productionListCard(p,'prontos')).join('')||'<div class="empty">Nenhum pedido aguardando entrega.</div>';
  const filtro=$('filtroFinalizados')?.value||'todos';
  const hist=finalizados.filter(p=>(filtro==='todos'||p.status===filtro)&&productionMatches(p)).sort((a,b)=>(b.atualizadoEm||'').localeCompare(a.atualizadoEm||''));
  if($('tabelaFinalizados'))$('tabelaFinalizados').innerHTML=hist.length?hist.map(p=>`<tr><td><b>${p.clienteNome||'-'}</b></td><td>${pedidoProdutosTexto(p)||'-'}</td><td>${p.entrega?dateBR.format(new Date(p.entrega+'T00:00:00')):'-'}</td><td>${p.atualizadoEm?dateBR.format(new Date(p.atualizadoEm)):'-'}</td><td>${fmt(p.valor)}</td><td>${p.pagamento||'-'}</td><td><span class="finalized-status ${p.status.toLowerCase()}">${p.status}</span></td><td><button class="btn light" onclick="editPedido('${p.id}')">Visualizar</button> <button class="btn light" onclick="reabrirPedido('${p.id}')">Reabrir</button></td></tr>`).join(''):'<tr><td colspan="8">Nenhum pedido finalizado.</td></tr>';
  setupKanbanDragDrop();
}
function setupKanbanDragDrop(){
  document.querySelectorAll('.kanban-card[draggable="true"]').forEach(card=>{
    card.addEventListener('dragstart',e=>{card.classList.add('dragging');e.dataTransfer.setData('text/plain',card.dataset.pedidoId)});
    card.addEventListener('dragend',()=>card.classList.remove('dragging'));
  });
  document.querySelectorAll('.kanban-col[data-status]').forEach(col=>{
    col.addEventListener('dragover',e=>{e.preventDefault();col.classList.add('drag-over')});
    col.addEventListener('dragleave',()=>col.classList.remove('drag-over'));
    col.addEventListener('drop',e=>{e.preventDefault();col.classList.remove('drag-over');const id=e.dataTransfer.getData('text/plain');if(id)window.movePedido(id,col.dataset.status)});
  });
}
window.registrarPagamentoRapido=id=>{const p=state.pedidos.find(x=>x.id===id);if(!p)return;const saldo=p.saldo??Math.max(0,(+p.valor||0)-(+p.sinal||0));const valor=prompt('Valor recebido:',saldo.toFixed(2));if(valor===null)return;const metodo=prompt('Forma de pagamento:',p.metodoRestante||'Pix');const temp=document.createElement('div');temp.innerHTML=`<input id="payValor_${id}" value="${String(valor).replace(',','.')}"><select id="payMetodo_${id}"><option>${metodo||'Pix'}</option></select>`;temp.style.display='none';document.body.appendChild(temp);window.registrarPagamentoPedido(id).finally(()=>temp.remove())};
