function dashboard(){const h=hoje(),m=mes(),vm=state.vendas.filter(v=>(v.data||'').startsWith(m)),cm=state.compras.filter(c=>(c.data||'').startsWith(m));const entradasHoje=state.financeiro.filter(f=>f.tipo==='receber'&&f.status==='Pago'&&f.data===h),entradasMes=state.financeiro.filter(f=>f.tipo==='receber'&&f.status==='Pago'&&(f.data||'').startsWith(m));const th=soma(entradasHoje,'valor'),tm=soma(entradasMes,'valor'),saidasPagas=state.financeiro.filter(f=>f.tipo==='pagar'&&f.status==='Pago'&&!f.estornado&&(f.dataPagamento||f.data||'').startsWith(m)),saida=soma(saidasPagas,'valor'),lucroBruto=soma(vm,'lucro'),despesasOperacionais=soma(saidasPagas.filter(f=>!f.compraId),'valor'),lucro=lucroBruto-despesasOperacionais;$('topHoje').textContent=$('dashHoje').textContent=fmt(th);$('dashEntradas').textContent=fmt(tm);$('dashSaidas').textContent=fmt(saida);$('dashLucro').textContent=fmt(lucro);$('dashPedidos').textContent=state.pedidos.filter(p=>!['Entregue','Cancelado'].includes(p.status)).length;const crit=state.produtos.filter(p=>(+p.estoque||0)<= (+p.minimo||0));$('dashEstoqueCritico').textContent=crit.length;$('alertasEstoque').innerHTML=crit.length?crit.map(p=>`<div class="rank"><b>${p.nome}</b><span>${p.estoque||0} un.</span></div>`).join(''):'<div class="empty">Nenhum item crítico.</div>';$('proximasEntregas').innerHTML=state.pedidos.filter(p=>p.entrega&&!['Entregue','Cancelado'].includes(p.status)).sort((a,b)=>a.entrega.localeCompare(b.entrega)).slice(0,6).map(p=>`<div class="rank"><b>${p.clienteNome}</b><span>${p.entrega}</span></div>`).join('')||'<div class="empty">Sem entregas próximas.</div>';charts(vm,tm,saida,lucro)}
function charts(vm,tm,saida,lucro){const dias=[];for(let i=6;i>=0;i--){const d=new Date();d.setDate(d.getDate()-i);dias.push(dataLocal(d))}const vals=dias.map(d=>soma(state.financeiro.filter(f=>f.tipo==='receber'&&f.status==='Pago'&&f.data===d),'valor')),labs=dias.map(d=>dateBR.format(new Date(d+'T00:00:00'))); if(chartDias)chartDias.destroy(); chartDias=new Chart($('graficoDias'),{type:'bar',data:{labels:labs,datasets:[{label:'Entradas recebidas',data:vals}]},options:{plugins:{legend:{display:false}}}}); const pags={'Dinheiro':0,'Pix':0,'Cartão de crédito':0,'Cartão de débito':0};state.financeiro.filter(f=>f.tipo==='receber'&&f.status==='Pago'&&(f.data||'').startsWith(mes())).forEach(f=>{const metodo=f.metodo||f.pagamento||'Não informado';pags[metodo]=(pags[metodo]||0)+(+f.valor||0)}); if(chartPag)chartPag.destroy(); chartPag=new Chart($('graficoPagamentos'),{type:'doughnut',data:{labels:Object.keys(pags),datasets:[{data:Object.values(pags)}]}}); if(chartResumo)chartResumo.destroy(); chartResumo=new Chart($('graficoResumo'),{type:'bar',data:{labels:['Entradas','Saídas','Saldo'],datasets:[{data:[tm,saida,lucro]}]},options:{plugins:{legend:{display:false}}}}); const rank={};vm.forEach(v=>(v.itens||[]).forEach(i=>rank[i.nome]=(rank[i.nome]||0)+(+i.quantidade||0)));const r=Object.entries(rank).sort((a,b)=>b[1]-a[1]).slice(0,7);$('ranking').innerHTML=r.length?r.map((x,i)=>`<div class="rank"><b>${i+1}. ${x[0]}</b><span>${x[1]} un.</span></div>`).join(''):'<div class="empty">Sem vendas no mês.</div>'}
