$('themeToggle')?.addEventListener('click',()=>{document.body.classList.toggle('dark-mode');localStorage.setItem('erp-theme',document.body.classList.contains('dark-mode')?'dark':'light')});if(localStorage.getItem('erp-theme')==='dark')document.body.classList.add('dark-mode');
$('notificationBtn')?.addEventListener('click',()=>{const n=+$('notificationCount').textContent||0;toast(n?`${n} alerta(s): verifique entregas, estoque e financeiro.`:'Nenhum alerta crítico no momento.')});

// ERP 2.1 - navegação interna dos módulos
const moduleViewMap={pedido:'pedidos',produto:'produtos',cliente:'clientes',fornecedor:'fornecedores',compra:'compras',financeiro:'financeiro'};
function showModuleList(module){
  const pageId=moduleViewMap[module]; if(!pageId)return;
  const page=document.getElementById(pageId); if(!page)return;
  page.querySelector(`[data-module-view="${module}-list"]`)?.classList.remove('hidden');
  page.querySelector(`[data-module-view="${module}-form"]`)?.classList.add('hidden');
  page.querySelector('.module-page-head')?.classList.remove('hidden');
  window.scrollTo({top:0,behavior:'smooth'});
}
function showModuleForm(module){
  const pageId=moduleViewMap[module]; if(!pageId)return;
  const page=document.getElementById(pageId); if(!page)return;
  page.querySelector(`[data-module-view="${module}-list"]`)?.classList.add('hidden');
  page.querySelector(`[data-module-view="${module}-form"]`)?.classList.remove('hidden');
  page.querySelector('.module-page-head')?.classList.add('hidden');
  window.scrollTo({top:0,behavior:'smooth'});
}
window.openModuleForm=showModuleForm;
window.openModuleList=showModuleList;
document.querySelectorAll('.module-new-btn').forEach(btn=>btn.addEventListener('click',()=>{
  const m=btn.dataset.module;
  const form=document.querySelector(`[data-module-view="${m}-form"] form`); form?.reset();
  const id=form?.querySelector('input[type="hidden"]'); if(id)id.value='';
  if(m==='pedido'){state.pedidoItens=[];renderPedidoItens();updatePedidoSaldo()}
  showModuleForm(m);
}));
document.querySelectorAll('.module-back-btn').forEach(btn=>btn.addEventListener('click',()=>showModuleList(btn.dataset.module)));
document.querySelectorAll('.nav[data-page], [data-go]').forEach(btn=>btn.addEventListener('click',()=>{
  const page=btn.dataset.page||btn.dataset.go;
  const m=Object.keys(moduleViewMap).find(k=>moduleViewMap[k]===page); if(m)setTimeout(()=>showModuleList(m),0);
}));

// Ao editar, abrir o formulário em sua própria área
const _editPedido=window.editPedido; window.editPedido=id=>{_editPedido(id);setTimeout(()=>showModuleForm('pedido'),0)};
const _editProduto=window.editProduto; window.editProduto=id=>{_editProduto(id);setTimeout(()=>showModuleForm('produto'),0)};
const _editCliente=window.editCliente; window.editCliente=id=>{_editCliente(id);setTimeout(()=>showModuleForm('cliente'),0)};
const _editFornecedor=window.editFornecedor; window.editFornecedor=id=>{_editFornecedor(id);setTimeout(()=>showModuleForm('fornecedor'),0)};

// Cancelar volta para a listagem
['Pedido','Produto','Cliente','Fornecedor','Financeiro'].forEach(name=>{
  const el=document.getElementById('cancelar'+name); if(el)el.addEventListener('click',()=>showModuleList(name.toLowerCase()));
});
['pedidoForm','produtoForm','clienteForm','fornecedorForm','compraForm','financeiroForm'].forEach(id=>{
  const form=document.getElementById(id); if(!form)return;
  const m=id.replace('Form','').replace('pedido','pedido').replace('produto','produto').replace('cliente','cliente').replace('fornecedor','fornecedor').replace('compra','compra').replace('financeiro','financeiro');
  form.addEventListener('submit',()=>setTimeout(()=>showModuleList(m),700));
});

// ERP 2.2 - controles das áreas de produção
function setProductionView(view){
  productionView=view;
  document.querySelectorAll('.production-tab').forEach(btn=>btn.classList.toggle('active',btn.dataset.productionView===view));
  document.querySelectorAll('[data-production-panel]').forEach(panel=>panel.classList.toggle('hidden',panel.dataset.productionPanel!==view));
}
document.querySelectorAll('.production-tab').forEach(btn=>btn.addEventListener('click',()=>setProductionView(btn.dataset.productionView)));
document.querySelectorAll('[data-production-open]').forEach(btn=>btn.addEventListener('click',()=>{goToPage('producao');setProductionView(btn.dataset.productionOpen);document.querySelectorAll('[data-production-open]').forEach(x=>x.classList.toggle('active',x===btn))}));
['filtroResponsavelProducao','filtroProdutoProducao'].forEach(id=>$(id)?.addEventListener('change',renderKanban));
$('buscaProducao')?.addEventListener('input',renderKanban);
$('filtroPrazoProducao')?.addEventListener('change',renderKanban);
$('filtroFinalizados')?.addEventListener('change',renderKanban);
$('limparFiltrosProducao')?.addEventListener('click',()=>{if($('buscaProducao'))$('buscaProducao').value='';if($('filtroPrazoProducao'))$('filtroPrazoProducao').value='todos';if($('filtroFinalizados'))$('filtroFinalizados').value='todos';renderKanban()});
$('novoPedidoProducao')?.addEventListener('click',()=>{goToPage('pedidos');setTimeout(()=>{document.querySelector('.module-new-btn[data-module="pedido"]')?.click()},0)});


// ERP 2.4 - Caixa e recebimentos consistentes
const metodosPadrao=['Dinheiro','Pix','Cartão de débito','Cartão de crédito','Transferência','Boleto','Outro'];
function normalizarMetodo(v){const x=(v||'').toLowerCase();if(x.includes('dinheiro'))return'Dinheiro';if(x.includes('pix'))return'Pix';if(x.includes('débito')||x.includes('debito'))return'Cartão de débito';if(x.includes('crédito')||x.includes('credito'))return'Cartão de crédito';if(x.includes('transfer'))return'Transferência';if(x.includes('boleto'))return'Boleto';return'Outro'}
function recebimentosPedido(id){return state.financeiro.filter(f=>f.pedidoId===id&&f.tipo==='receber'&&f.status==='Pago'&&!f.estornado)}
function totalRecebidoPedido(id){return soma(recebimentosPedido(id),'valor')}
async function sincronizarPedidoFinanceiro(id){const p=state.pedidos.find(x=>x.id===id);if(!p)return;const pago=totalRecebidoPedido(id),saldo=Math.max(0,(+p.valor||0)-pago);await updateDoc(doc(db,'pedidos',id),{sinal:pago,saldo,pagamento:saldo===0?'Pago':pago>0?'Sinal pago':'Pendente',atualizadoEm:new Date().toISOString()})}
window.registrarPagamentoPedido=async id=>{const p=state.pedidos.find(x=>x.id===id);if(!p)return;const saldo=Math.max(0,(+p.valor||0)-totalRecebidoPedido(id));const el=$('payValor_'+id),valor=+(el?.value||0),metodo=normalizarMetodo($('payMetodo_'+id)?.value||p.metodoRestante||'Pix');if(valor<=0)return toast('Informe um valor válido.');if(valor>saldo+0.001)return toast('O recebimento não pode ser maior que o saldo de '+fmt(saldo)+'.');await addDoc(collection(db,'financeiro'),{tipo:'receber',descricao:valor<saldo?'Pagamento parcial do pedido':'Quitação do pedido',pessoa:p.clienteNome||'',valor,metodo,vencimento:hoje(),status:'Pago',data:hoje(),dataPagamento:hoje(),competencia:mes(),pedidoId:id,operador:state.user?.email||'',criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});await refresh();await sincronizarPedidoFinanceiro(id);toast(valor<saldo?'Pagamento parcial registrado':'Pedido quitado');refresh()}
window.estornarRecebimento=async id=>{const f=state.financeiro.find(x=>x.id===id);if(!f||f.tipo!=='receber'||f.status!=='Pago')return;if(!confirm('Estornar este recebimento? O histórico será preservado.'))return;await updateDoc(doc(db,'financeiro',id),{status:'Estornado',estornado:true,estornadoEm:new Date().toISOString(),estornadoPor:state.user?.email||''});await refresh();if(f.pedidoId)await sincronizarPedidoFinanceiro(f.pedidoId);toast('Recebimento estornado');refresh()}
window.delFin=async id=>{const f=state.financeiro.find(x=>x.id===id);if(f?.pedidoId||f?.compraId)return toast('Lançamentos vinculados não podem ser excluídos. Use estorno.');if(confirm('Excluir lançamento manual?')){await deleteDoc(doc(db,'financeiro',id));refresh()}}
function renderFinanceiro(){const validos=state.financeiro.filter(f=>f.status!=='Estornado'&&!f.estornado),pend=validos.filter(f=>f.status!=='Pago'),rec=soma(pend.filter(f=>f.tipo==='receber'),'valor'),pag=soma(pend.filter(f=>f.tipo==='pagar'),'valor'),venc=pend.filter(f=>f.vencimento&&f.vencimento<hoje()).length;$('finReceber').textContent=fmt(rec);$('finPagar').textContent=fmt(pag);$('finSaldo').textContent=fmt(rec-pag);$('finVencidas').textContent=venc;$('listaFinanceiro').innerHTML=state.financeiro.length?state.financeiro.map(f=>`<div class="info"><div><strong>${f.tipo==='receber'?'A receber':'A pagar'} - ${f.descricao}</strong><small>${f.pessoa||'-'} | Venc.: ${f.vencimento||'-'} | ${fmt(f.valor)} | ${normalizarMetodo(f.metodo)}</small><small>Status: ${f.status}${f.dataPagamento?' | Pago em: '+f.dataPagamento:''}</small></div><div>${f.tipo==='receber'&&f.status==='Pago'?`<button class="btn danger" onclick="estornarRecebimento('${f.id}')">Estornar</button>`:`<button class="btn light" onclick="editFin('${f.id}')">Editar</button> <button class="btn danger" onclick="delFin('${f.id}')">Excluir</button>`}</div></div>`).join(''):'<div class="empty">Nenhum lançamento.</div>'}
function caixaAberto(){return state.caixas.find(c=>c.status==='Aberto')}
function renderCaixa(){if(!$('caixaStatus'))return;const c=caixaAberto(),mov=state.financeiro.filter(f=>f.caixaId===c?.id&&f.status==='Pago'&&!f.estornado),dinEntr=soma(mov.filter(f=>f.tipo==='receber'&&normalizarMetodo(f.metodo)==='Dinheiro'),'valor'),supr=soma(mov.filter(f=>f.movimentoCaixa==='Suprimento'),'valor'),sang=soma(mov.filter(f=>['Sangria','Despesa'].includes(f.movimentoCaixa)),'valor'),esperado=(+c?.saldoInicial||0)+dinEntr+supr-sang;$('caixaStatus').textContent=c?'Aberto':'Fechado';$('caixaInicial').textContent=fmt(c?.saldoInicial||0);$('caixaEntradas').textContent=fmt(dinEntr);$('caixaEsperado').textContent=fmt(esperado);$('listaCaixa').innerHTML=mov.length?mov.map(f=>`<div class="info"><div><strong>${f.movimentoCaixa||f.descricao}</strong><small>${f.dataPagamento||f.data||'-'} | ${normalizarMetodo(f.metodo)} | ${fmt(f.valor)}</small></div></div>`).join(''):'<div class="empty">Nenhuma movimentação no caixa atual.</div>'}
$('abrirCaixa')?.addEventListener('click',async()=>{if(caixaAberto())return toast('Já existe um caixa aberto.');const saldoInicial=+$('caixaSaldoInicial').value||0;await addDoc(collection(db,'caixas'),{status:'Aberto',saldoInicial,operador:state.user?.email||'',data:hoje(),abertoEm:new Date().toISOString(),timestamp:serverTimestamp()});toast('Caixa aberto');refresh()});
$('registrarMovCaixa')?.addEventListener('click',async()=>{const c=caixaAberto();if(!c)return toast('Abra o caixa primeiro.');const tipo=$('caixaMovTipo').value,valor=+$('caixaMovValor').value||0,descricao=$('caixaMovDescricao').value.trim();if(valor<=0||!descricao)return toast('Informe descrição e valor.');await addDoc(collection(db,'financeiro'),{tipo:tipo==='Suprimento'?'receber':'pagar',descricao,pessoa:'Caixa',valor,metodo:'Dinheiro',vencimento:hoje(),status:'Pago',data:hoje(),dataPagamento:hoje(),competencia:mes(),caixaId:c.id,movimentoCaixa:tipo,operador:state.user?.email||'',criadoEm:new Date().toISOString(),timestamp:serverTimestamp()});toast('Movimentação registrada');refresh()});
$('fecharCaixa')?.addEventListener('click',async()=>{const c=caixaAberto();if(!c)return toast('Não existe caixa aberto.');const contado=+$('caixaContado').value||0,mov=state.financeiro.filter(f=>f.caixaId===c.id&&f.status==='Pago'&&!f.estornado),dinEntr=soma(mov.filter(f=>f.tipo==='receber'&&normalizarMetodo(f.metodo)==='Dinheiro'),'valor'),supr=soma(mov.filter(f=>f.movimentoCaixa==='Suprimento'),'valor'),sang=soma(mov.filter(f=>['Sangria','Despesa'].includes(f.movimentoCaixa)),'valor'),esperado=(+c.saldoInicial||0)+dinEntr+supr-sang;await updateDoc(doc(db,'caixas',c.id),{status:'Fechado',fechadoEm:new Date().toISOString(),dinheiroContado:contado,saldoEsperado:esperado,diferenca:contado-esperado,fechadoPor:state.user?.email||''});toast('Caixa fechado. Diferença: '+fmt(contado-esperado));refresh()});
